const STATUS_KEY="bayamon_cisternas_status_v3";
const COLORS={"Impedimento / encamados":"#d7191c","Mayores de 60 años":"#f59e0b","Hogares con niños":"#2b83ba","Otros registros":"#68707a"};
let statusStore=JSON.parse(localStorage.getItem(STATUS_KEY)||"{}");
let map=L.map("map").setView([18.36,-66.16],12);
L.tileLayer("https://{s}.tile.openstreetmap.org/{z}/{x}/{y}.png",{maxZoom:20,attribution:"&copy; OpenStreetMap"}).addTo(map);
let zoneLayer=L.layerGroup().addTo(map), pointLayer=L.layerGroup(), markers=new Map();

function statusOf(pin){return statusStore[pin]||"Pendiente"}
function saveStatus(pin,val){statusStore[pin]=val;localStorage.setItem(STATUS_KEY,JSON.stringify(statusStore));render()}
function esc(s){return String(s||"").replace(/[&<>"']/g,m=>({'&':'&amp;','<':'&lt;','>':'&gt;','"':'&quot;',"'":'&#039;'}[m]))}
function cats(){return [...document.querySelectorAll(".cat:checked")].map(x=>x.value)}
function searchText(r){return `${r.pin} ${r.orden} ${r.nombre} ${r.telefono} ${r.sector} ${r.calle} ${r.estructura} ${r.categoria}`.toLowerCase()}
function filtered(){
  const q=document.getElementById("q").value.trim().toLowerCase(),s=document.getElementById("sector").value,e=document.getElementById("estado").value,a=cats(),mode=document.getElementById("mode").value;
  return DATA.filter(r=>a.includes(r.categoria)).filter(r=>!s||r.sector===s).filter(r=>!e||statusOf(r.pin)===e).filter(r=>mode!=="priority"||["Impedimento / encamados","Mayores de 60 años"].includes(r.categoria)).filter(r=>!q||searchText(r).includes(q)).sort((a,b)=>a.orden-b.orden)
}
function dominant(rows){
  const c={"Impedimento / encamados":0,"Mayores de 60 años":0,"Hogares con niños":0,"Otros registros":0};
  rows.forEach(r=>c[r.categoria]++);
  return Object.entries(c).sort((a,b)=>b[1]-a[1])[0][0];
}
function buildZones(rows){
  const z={};
  rows.forEach(r=>{
    const key=(Math.round(r.lat*500)/500).toFixed(3)+","+(Math.round(r.lon*500)/500).toFixed(3);
    if(!z[key]) z[key]=[];
    z[key].push(r);
  });
  return Object.values(z).map(rows=>{
    const lat=rows.reduce((s,r)=>s+r.lat,0)/rows.length;
    const lon=rows.reduce((s,r)=>s+r.lon,0)/rows.length;
    return {lat,lon,rows,cat:dominant(rows),count:rows.length};
  });
}
function zoneIcon(z){
  const color=COLORS[z.cat]||"#68707a";
  const size=Math.min(70,Math.max(32,24+Math.sqrt(z.count)*8));
  return L.divIcon({className:"",html:`<div class="zoneMarker" style="background:${color};width:${size}px;height:${size}px;font-size:${size>50?18:14}px">${z.count}</div>`,iconSize:[size,size],iconAnchor:[size/2,size/2]});
}
function pointIcon(r){
  const color=COLORS[r.categoria]||"#68707a";
  return L.divIcon({className:"",html:`<div class="pointMarker" style="background:${color}"></div>`,iconSize:[16,16],iconAnchor:[8,8]});
}
function popupCase(r){
  const st=statusOf(r.pin);
  return `<div class="popup"><h3>PIN ${r.pin} <span style="font-size:12px;color:#667085">Orden ${r.orden}</span></h3><table><tr><td>Categoría</td><td>${esc(r.categoria)}</td></tr><tr><td>Estado</td><td><b>${esc(st)}</b></td></tr><tr><td>Nombre</td><td>${esc(r.nombre)}</td></tr><tr><td>Teléfono</td><td>${esc(r.telefono)}</td></tr><tr><td>Sector</td><td>${esc(r.sector)}</td></tr><tr><td>Dirección</td><td>${esc(r.calle)} ${esc(r.estructura)}</td></tr><tr><td>Mayores</td><td>${esc(r.mayores60)}</td></tr><tr><td>Menores</td><td>${esc(r.menores17)}</td></tr><tr><td>Equipo</td><td>${esc(r.equipo)}</td></tr></table><label>Cambiar estado</label><select onchange="saveStatus(${r.pin},this.value)"><option ${st==="Pendiente"?"selected":""}>Pendiente</option><option ${st==="En ruta"?"selected":""}>En ruta</option><option ${st==="Entregada"?"selected":""}>Entregada</option><option ${st==="No localizado"?"selected":""}>No localizado</option></select></div>`;
}
function popupZone(z){
  const c={"Impedimento / encamados":0,"Mayores de 60 años":0,"Hogares con niños":0,"Otros registros":0};
  z.rows.forEach(r=>c[r.categoria]++);
  return `<div class="popup"><h3>Zona operacional</h3><table><tr><td>Total</td><td><b>${z.count}</b></td></tr><tr><td>Impedimento</td><td>${c["Impedimento / encamados"]}</td></tr><tr><td>Mayores</td><td>${c["Mayores de 60 años"]}</td></tr><tr><td>Niños</td><td>${c["Hogares con niños"]}</td></tr><tr><td>Otros</td><td>${c["Otros registros"]}</td></tr></table><button style="margin-top:10px;width:100%" onclick="map.setView([${z.lat},${z.lon}],17);document.getElementById('mode').value='points';render()">Ver puntos de esta zona</button></div>`;
}
function render(){
  const rows=filtered(),mode=document.getElementById("mode").value;
  zoneLayer.clearLayers();pointLayer.clearLayers();markers.clear();
  if(mode==="points"){
    if(map.hasLayer(zoneLayer)) map.removeLayer(zoneLayer); if(!map.hasLayer(pointLayer)) map.addLayer(pointLayer);
    rows.forEach(r=>{const m=L.marker([r.lat,r.lon],{icon:pointIcon(r)}).bindPopup(popupCase(r));markers.set(r.pin,m);pointLayer.addLayer(m)});
    updatePanel(rows,0);
  } else {
    if(map.hasLayer(pointLayer)) map.removeLayer(pointLayer); if(!map.hasLayer(zoneLayer)) map.addLayer(zoneLayer);
    const zones=buildZones(rows);
    zones.forEach(z=>L.marker([z.lat,z.lon],{icon:zoneIcon(z)}).bindPopup(popupZone(z)).addTo(zoneLayer));
    updatePanel(rows,zones.length);
  }
}
function updatePanel(rows,zones){
  const c={"Pendiente":0,"En ruta":0,"Entregada":0,"No localizado":0}; rows.forEach(r=>c[statusOf(r.pin)]++);
  document.getElementById("totalVisible").textContent=rows.length;document.getElementById("zonasVisible").textContent=zones;document.getElementById("pendientes").textContent=c["Pendiente"]||0;document.getElementById("entregadas").textContent=c["Entregada"]||0;
  document.getElementById("countText").textContent=`${rows.length} registros visibles de ${DATA.length} total`;
  const list=document.getElementById("list");list.innerHTML="";
  rows.slice(0,160).forEach(r=>{const d=document.createElement("div");d.className="item";d.innerHTML=`<b>PIN ${r.pin} · Orden ${r.orden}</b><small>${esc(r.nombre||"Sin nombre")}</small><small>${esc(r.categoria)} · ${esc(r.sector)} · Estado: <b>${esc(statusOf(r.pin))}</b></small>`;d.onclick=()=>{document.getElementById("mode").value="points";render();map.setView([r.lat,r.lon],18);setTimeout(()=>{const m=markers.get(r.pin);if(m)m.openPopup()},100)};list.appendChild(d)})
}
function fitVisible(){const rows=filtered(); if(!rows.length)return; map.fitBounds(L.latLngBounds(rows.map(r=>[r.lat,r.lon])).pad(.08))}
function resetAll(){document.getElementById("q").value="";document.getElementById("sector").value="";document.getElementById("estado").value="";document.getElementById("mode").value="zones";document.querySelectorAll(".cat").forEach(x=>x.checked=true);render();setTimeout(fitVisible,150)}
function exportCSV(){const rows=filtered(),h=["PIN","ORDEN","ESTADO","CATEGORIA","NOMBRE","TELEFONO","SECTOR","CALLE","ESTRUCTURA","LAT","LON"],lines=[h.join(",")];rows.forEach(r=>lines.push([r.pin,r.orden,statusOf(r.pin),r.categoria,r.nombre,r.telefono,r.sector,r.calle,r.estructura,r.lat,r.lon].map(v=>`"${String(v||"").replace(/"/g,'""')}"`).join(",")));const blob=new Blob([lines.join("\\n")],{type:"text/csv;charset=utf-8"}),url=URL.createObjectURL(blob),a=document.createElement("a");a.href=url;a.download="cisternas_bayamon_v3.csv";a.click();URL.revokeObjectURL(url)}
function init(){const sectors=[...new Set(DATA.map(r=>r.sector||"Sin sector"))].sort((a,b)=>a.localeCompare(b)),sel=document.getElementById("sector");sectors.forEach(s=>{const o=document.createElement("option");o.value=s;o.textContent=s;sel.appendChild(o)});["q","sector","estado","mode"].forEach(id=>document.getElementById(id).addEventListener("input",render));document.querySelectorAll(".cat").forEach(c=>c.addEventListener("change",render));render();setTimeout(fitVisible,250)}
init();
